// Check if the barracks tower has non-identity transform that might affect child RBs
var barracks = UnityEngine.Object.FindObjectOfType<TowerDefense.Tower.BarracksAttack>();
if (barracks != null)
{
    var tower = barracks.transform;
    UnityEngine.Debug.Log($"[DIAG] Tower: {barracks.gameObject.name}");
