    // Check soldiers parent
    var soldiers = UnityEngine.Object.FindObjectsOfType<TowerDefense.Tower.Soldier>();
    foreach (var s in soldiers)
    {
        UnityEngine.Debug.Log($"[DIAG] Soldier: {s.gameObject.name} parent={s.transform.parent?.name ?? "none"}");
        UnityEngine.Debug.Log($"[DIAG]   localPos={s.transform.localPosition} worldPos={s.transform.position}");
    }
}

