args.script:
// Place a barracks tower on a slot near the enemy path
var slots = UnityEngine.Object.FindObjectsOfType<TowerDefense.Tower.TowerSlot>();
var enemies = UnityEngine.Object.FindObjectsOfType<TowerDefense.Enemy.Enemy>();
if (enemies.Length == 0) { UnityEngine.Debug.Log("[DIAG] No enemies"); return; }

var enemyPos = enemies[0].transform.position;

// Find closest available slot to the first enemy
TowerDefense.Tower.TowerSlot bestSlot = null;
float bestDist = float.MaxValue;
foreach (var slot in slots)
{
    if (slot.HasTower) continue;
    float dist = UnityEngine.Vector3.Distance(slot.transform.position, enemyPos);
    if (dist < bestDist && dist > 1f && dist < 4f)
    {
        bestDist = dist;
        bestSlot = slot;
    }
}

if (bestSlot != null)
{
    var barracksData = UnityEditor.AssetDatabase.LoadAssetAtPath<TowerDefense.Data.TowerData>("Assets/Resources/Data/Towers/Barracks.asset");
    if (barracksData != null)
    {
        bestSlot.PlaceTower(barracksData);
        UnityEngine.Debug.Log($"[DIAG] Placed barracks at slot {bestSlot.name} pos={bestSlot.transform.position}");
    }
    else
    {
        UnityEngine.Debug.Log("[DIAG] Barracks data is null!");
    }
}
else
{
    UnityEngine.Debug.Log("[DIAG] No suitable slot found");
}

