static void CreateRunClip()
{
    // Run: bouncing movement (walk cycle feel)
    var clip = new AnimationClip();
    clip.name = "SoldierKnight_FrontRun";

    // Y position bounce - faster bob for running
    var curve = new AnimationCurve(
        new Keyframe(0f, 0f, 0f, 0f),
        new Keyframe(0.25f, 0.08f, 0f, 0f),
        new Keyframe(0.5f, 0f, 0f, 0f),
        new Keyframe(0.75f, 0.08f, 0f, 0f),
        new Keyframe(1f, 0f, 0f, 0f)
    );
    clip.SetCurve("", typeof(Transform), "m_LocalPosition.y", curve);

    // Slight horizontal tilt
    var tiltCurve = new AnimationCurve(
        new Keyframe(0f, 0f, 0f, 0f),
        new Keyframe(0.25f, -3f, 0f, 0f),
        new Keyframe(0.5f, 0f, 0f, 0f),
        new Keyframe(0.75f, 3f, 0f, 0f),
        new Keyframe(1f, 0f, 0f, 0f)
    );
    clip.SetCurve("", typeof(Transform), "localEulerAnglesRaw.z", tiltCurve);

    // Scale bounce
    var scaleY = new AnimationCurve(
        new Keyframe(0f, 1f, 0f, 0f),
        new Keyframe(0.25f, 1.05f, 0f, 0f),
        new Keyframe(0.5f, 0.98f, 0f, 0f),
        new Keyframe(0.75f, 1.05f, 0f, 0f),
        new Keyframe(1f, 1f, 0f, 0f)
    );
    clip.SetCurve("", typeof(Transform), "m_LocalScale.y", scaleY);

    AssetDatabase.CreateAsset(clip, RunClipPath);
    SetClipLoopTime(clip);
    EditorUtility.SetDirty(clip);
    Debug.Log($"[SoldierAnimatorSetup] Created run clip: {RunClipPath}");
}

